-- Initialize TikTok Clone Database\n\n-- Create extensions\nCREATE EXTENSION IF NOT EXISTS \"uuid-ossp\";\nCREATE EXTENSION IF NOT EXISTS \"pgcrypto\";\n\n-- Create schemas\nCREATE SCHEMA IF NOT EXISTS public;\nCREATE SCHEMA IF NOT EXISTS audit;\n\n-- Audit trigger function\nCREATE OR REPLACE FUNCTION audit.audit_trigger()\nRETURNS TRIGGER AS $$\nBEGIN\n    INSERT INTO audit.audit_log (table_name, record_id, action, old_data, new_data, changed_by, changed_at)\n    VALUES (\n        TG_TABLE_NAME,\n        COALESCE(NEW.id, OLD.id),\n        TG_OP,\n        to_jsonb(OLD),\n        to_jsonb(NEW),\n        CURRENT_USER,\n        CURRENT_TIMESTAMP\n    );\n    RETURN COALESCE(NEW, OLD);\nEND;\n$$ LANGUAGE plpgsql;\n\n-- Audit log table\nCREATE TABLE IF NOT EXISTS audit.audit_log (\n    id BIGSERIAL PRIMARY KEY,\n    table_name TEXT NOT NULL,\n    record_id UUID,\n    action TEXT NOT NULL,\n    old_data JSONB,\n    new_data JSONB,\n    changed_by TEXT,\n    changed_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,\n    created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Create indexes for audit log\nCREATE INDEX IF NOT EXISTS idx_audit_table_name ON audit.audit_log(table_name);\nCREATE INDEX IF NOT EXISTS idx_audit_record_id ON audit.audit_log(record_id);\nCREATE INDEX IF NOT EXISTS idx_audit_created_at ON audit.audit_log(created_at DESC);\n\n-- Grant permissions\nGRANT USAGE ON SCHEMA public TO user;\nGRANT USAGE ON SCHEMA audit TO user;\n\necho 'Database initialization script completed';\n